  ('optometrist-moex-03324', 'optometrist', 'optometrist-moex-106-b0a2f330', 'sub-optometrist-02', NULL, 'single_choice', '驗光師執業，應接受下列課程之繼續教育：一、專業課程。二、專業品質。三、專業倫理。四、專業相', '["每六年應完成前項繼續教育課程之積分數72點", "申請執業更新時， 其前一年繼續教育課程總積分需占全部積分六分之一以上", "繼續教育前述第二至第四項課程之積分 數，合計至少十二點", "於偏遠地區執業期間，其各點實施方式之積分數，得以一點五倍計"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:55+00:00", "source_pdf_sha1": "5e2676c5266b", "answer_pdf_sha1": "6f22ec09b07e", "source_family": "moex-gov-tw", "moex": {"exam_code": "106060", "c": "401", "s": "0801", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "眼球解剖生理學與倫理法規", "year": "106", "exam_name": "106年專技人員高等考試大地工程技師考試分階段考試、驗船師、引水人、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政士、專責...", "original_question_number": 47, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-03325', 'optometrist', 'optometrist-moex-106-b0a2f330', 'sub-optometrist-02', NULL, 'single_choice', '隱形眼鏡之驗光配鏡係屬醫療行為，對於十五歲以上的對象，以下何者正確？', '["所有隱形眼鏡之驗光配鏡限由醫師為之", "驗光師可獨立執行近視、遠視、散光的隱形眼鏡之驗光配鏡", "驗光師可獨立執行角膜塑形鏡片之驗光配鏡", "驗光師可獨立執行矯正圓錐角膜隱形眼鏡之驗光配鏡"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:55+00:00", "source_pdf_sha1": "5e2676c5266b", "answer_pdf_sha1": "6f22ec09b07e", "source_family": "moex-gov-tw", "moex": {"exam_code": "106060", "c": "401", "s": "0801", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "眼球解剖生理學與倫理法規", "year": "106", "exam_name": "106年專技人員高等考試大地工程技師考試分階段考試、驗船師、引水人、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政士、專責...", "original_question_number": 48, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-03326', 'optometrist', 'optometrist-moex-106-b0a2f330', 'sub-optometrist-02', NULL, 'single_choice', '下列有關驗光人員申請設立驗光所之敘述，何者正確？', '["申請設立驗光所之驗光師，以在驗光人員法第九條所定之機構執行業務三年以上者為限", "申請設立驗光所之驗光生，以在驗光人員法第九條所定之機構執行業務六年以上者為限", "執行業務年資之採計，以領有驗光人員證書並依法向直轄市、縣（市）主管機關辦理執業登記者為限", "執業年資限由驗光人員法公布施行後開始採計"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:55+00:00", "source_pdf_sha1": "5e2676c5266b", "answer_pdf_sha1": "6f22ec09b07e", "source_family": "moex-gov-tw", "moex": {"exam_code": "106060", "c": "401", "s": "0801", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "眼球解剖生理學與倫理法規", "year": "106", "exam_name": "106年專技人員高等考試大地工程技師考試分階段考試、驗船師、引水人、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政士、專責...", "original_question_number": 49, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-03327', 'optometrist', 'optometrist-moex-106-b0a2f330', 'sub-optometrist-02', NULL, 'single_choice', '隱形眼鏡係屬列管之醫療器材，有關隱形眼鏡的販賣，下列何者正確？', '["驗光所只能裝配隱形眼鏡，絕對禁止販賣隱形眼鏡", "有合格驗光人員執業的驗光所，即可經營隱形眼鏡販賣業務", "驗光所必須申請醫療器材販賣業藥商許可執照，方可經營隱形眼鏡販賣業務", "驗光所必須申請醫療器材販賣業藥商許可執照，並有合格藥師執業，方可經營隱形眼鏡販賣業務"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:55+00:00", "source_pdf_sha1": "5e2676c5266b", "answer_pdf_sha1": "6f22ec09b07e", "source_family": "moex-gov-tw", "moex": {"exam_code": "106060", "c": "401", "s": "0801", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "眼球解剖生理學與倫理法規", "year": "106", "exam_name": "106年專技人員高等考試大地工程技師考試分階段考試、驗船師、引水人、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政士、專責...", "original_question_number": 50, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-03328', 'optometrist', 'optometrist-moex-106-c33a0f9f', 'sub-optometrist-03', NULL, 'single_choice', '假設受檢者是順規（with-the-rule）的混合性散光（mixed astigmatism），而散光是由角膜引起的話，當受 檢者檢查視力看遠方視標時，經過眼睛折射而形成的影像，下列敘述何者正確？', '["角膜垂直方向比較平坦，在視網膜之前形成一條水平橫向焦線，在視網膜之後形成一條垂直豎立焦線", "角膜垂直方向比較平坦，在視網膜之前形成一條垂直豎立焦線，在視網膜之後形成一條水平橫向焦線", "角膜水平方向比較平坦，在視網膜之前形成一條水平橫向焦線，在視網膜之後形成一條垂直豎立焦線", "角膜水平方向比較平坦，在視網膜之前形成一條垂直豎立焦線，在視網膜之後形成一條水平橫向焦線"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:55+00:00", "source_pdf_sha1": "d48b9e09da91", "answer_pdf_sha1": "3dd3238e5460", "source_family": "moex-gov-tw", "moex": {"exam_code": "106110", "c": "112", "s": "1103", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "視光學", "year": "106", "exam_name": "106年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、106年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 1, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-03329', 'optometrist', 'optometrist-moex-106-c33a0f9f', 'sub-optometrist-03', NULL, 'single_choice', '受檢者看遠方需要加上 planoDS/-1.50DC×090 的眼鏡矯正，當他接受裸眼視力檢查，使用史耐倫 E （Snellen E）視標，經過眼睛折射在視網膜上的成像是：', '["視網膜的位置形成一條垂直豎立焦線，E形視標開口在上下方向線條比較容易辨別", "視網膜的位置形成一條垂直豎立焦線，E形視標開口在左右方向線條比較容易辨別", "視網膜的位置形成一條水平橫向焦線，E形視標開口在上下方向線條比較容易辨別", "視網膜的位置形成一條水平橫向焦線，E形視標開口在左右方向線條比較容易辨別"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:55+00:00", "source_pdf_sha1": "d48b9e09da91", "answer_pdf_sha1": "3dd3238e5460", "source_family": "moex-gov-tw", "moex": {"exam_code": "106110", "c": "112", "s": "1103", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "視光學", "year": "106", "exam_name": "106年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、106年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 2, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-03330', 'optometrist', 'optometrist-moex-106-c33a0f9f', 'sub-optometrist-03', NULL, 'single_choice', '受檢者看遠方需要加上-1.00DS/-1.00DC×090的眼鏡矯正。當他接受近視力檢查，未戴眼鏡而注視眼前 30公分的視標時，假設沒有用到調節功能，則經過眼睛折射後影像的位置：', '["水平主徑線的焦線在視網膜之前，垂直主徑線的焦線在視網膜之後", "水平主徑線的焦線在視網膜之後，垂直主徑線的焦線在視網膜之前", "水平主徑線以及垂直主徑線的焦線都在視網膜之前", "水平主徑線以及垂直主徑線的焦線都在視網膜之後"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:55+00:00", "source_pdf_sha1": "d48b9e09da91", "answer_pdf_sha1": "3dd3238e5460", "source_family": "moex-gov-tw", "moex": {"exam_code": "106110", "c": "112", "s": "1103", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "視光學", "year": "106", "exam_name": "106年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、106年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 3, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-03331', 'optometrist', 'optometrist-moex-106-c33a0f9f', 'sub-optometrist-03', NULL, 'single_choice', '看遠方時右眼需要配戴-3.00DS/-1.50DC×170的眼鏡矯正，左眼需要配戴-2.00DS/-2.00DC×010的眼鏡矯 正。按照此度數配好的眼鏡，其鏡片負圓柱透鏡的軸與水平方向比較：', '["兩眼的負圓柱透鏡軸都向鼻內側傾斜10度", "兩眼的負圓柱透鏡軸都向耳外側傾斜10度", "兩眼的負圓柱透鏡軸都向戴用者的右側傾斜10度", "兩眼的負圓柱透鏡軸都向戴用者的左側傾斜10度"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:55+00:00", "source_pdf_sha1": "d48b9e09da91", "answer_pdf_sha1": "3dd3238e5460", "source_family": "moex-gov-tw", "moex": {"exam_code": "106110", "c": "112", "s": "1103", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "視光學", "year": "106", "exam_name": "106年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、106年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 4, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-03332', 'optometrist', 'optometrist-moex-106-c33a0f9f', 'sub-optometrist-03', NULL, 'single_choice', '下列何種遠視，測量的時候通常需要使用到睫狀肌麻痺劑？', '["顯性遠視（manifest hyperopia）", "機能遠視（facultative hyperopia）", "隱性遠視（latent hyperopia）", "絕對遠視（absolute hyperopia）"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:55+00:00", "source_pdf_sha1": "d48b9e09da91", "answer_pdf_sha1": "3dd3238e5460", "source_family": "moex-gov-tw", "moex": {"exam_code": "106110", "c": "112", "s": "1103", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "視光學", "year": "106", "exam_name": "106年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、106年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 5, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
